async (params, browser) => {
  // Open Slack
  await browser.open('https://app.slack.com')

  // Let Slack load
  await browser.wait(3000)

  // Set status via Slack API
  const result = await browser.evaluate(`const localConfig = localStorage.getItem('localConfig_v2'); if (!localConfig) throw new Error('Not logged into Slack'); const config = JSON.parse(localConfig); const teamId = Object.keys(config.teams)[0]; const token = config.teams[teamId].token; const profile = { status_text: params.status_text, status_emoji: params.status_emoji }; const resp = await fetch('/api/users.profile.set', { method: 'POST', headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' }, body: JSON.stringify({ profile }) }); const data = await resp.json(); if (!data.ok) throw new Error('Status update failed: ' + data.error); return { success: true, status_text: profile.status_text, status_emoji: profile.status_emoji }`)

  return result
}
